// ═══════════════════════════════════════════════════════
// DECODIFICACIÓN COMPLETA DE DATOS SAI - ACT350
// Protocolo: SAI sobre EtherNet/IP
// Formato: 2 Bloques (Assembly 101, 16 bytes, Little Endian)
// ═══════════════════════════════════════════════════════

const raw = msg.raw;

// ── 1. BLOQUE DE MEDICIÓN (Bytes 0-7) ──
const weight = parseFloat(raw.measureValue.toFixed(4));
const ds = raw.deviceStatus;  // UINT16 con 16 bits de estado
const resp = raw.mbResponse;  // INT16 con respuesta al comando

// Decodificar cada bit del Device Status
const sequenceBits = ds & 0x03;           // Bits 0-1: toggle de secuencia
const heartbeat    = (ds >> 2) & 1;       // Bit 2: pulso de vida (~1s)
const dataOk       = (ds >> 3) & 1;       // Bit 3: datos válidos
const alarmCond    = (ds >> 4) & 1;       // Bit 4: alarma activa
const centerOfZero = (ds >> 5) & 1;       // Bit 5: en centro de cero
const motion       = (ds >> 6) & 1;       // Bit 6: inestabilidad
const netMode      = (ds >> 7) & 1;       // Bit 7: modo peso neto
const altUnit      = (ds >> 8) & 1;       // Bit 8: unidad alternativa

// Decodificar MB Response
const respValue   = resp & 0x07FF;        // Bits 0-10: código de respuesta
const respChannel = (resp >> 11) & 0x0F;  // Bits 11-14: canal
const respError   = (resp >> 15) & 1;     // Bit 15: flag de error

// ── 2. BLOQUE DE STATUS (Bytes 8-15) ──
const sg1 = raw.statusGroup1;  // RedAlert Alarms
const sg2 = raw.statusGroup2;  // Scale Status
const sg3 = raw.statusGroup3;  // I/O Status

// RedAlert Alarms (Status Group 1)
const redAlert = {
    calibrationError:    (sg1 >> 0) & 1,
    outOfADRange:        (sg1 >> 1) & 1,
    checksumFailure:     (sg1 >> 2) & 1,
    weightBlocked:       (sg1 >> 3) & 1,
    sensorCommFailure:   (sg1 >> 4) & 1,
    overload:            (sg1 >> 5) & 1,
    underload:           (sg1 >> 6) & 1,
    networkFailure:      (sg1 >> 7) & 1,
    zeroOutOfRange:      (sg1 >> 8) & 1,
    symmetryError:       (sg1 >> 9) & 1,
    temperatureError:    (sg1 >> 10) & 1,
    wmFailure:           (sg1 >> 11) & 1,
    foreignDevice:       (sg1 >> 12) & 1,
    testMode:            (sg1 >> 13) & 1
};

// Scale Status (Status Group 2)
const unitBits = sg2 & 0x0F;
const unitMap = {0:'g', 1:'kg', 2:'lb', 3:'t', 4:'ton', 7:'custom'};
const weightUnit    = unitMap[unitBits] || 'desconocida';
const minWeighError = (sg2 >> 4) & 1;
const rangeBits     = (sg2 >> 5) & 0x03;
const inSetup       = (sg2 >> 7) & 1;
const puzFail       = (sg2 >> 8) & 1;  // Power Up Zero Failure
const gwpOutTol     = (sg2 >> 9) & 1;

// I/O Status (Status Group 3)
const ioIn  = sg3 & 0xFF;          // Bits 0-7: entradas 1-8
const ioOut = (sg3 >> 8) & 0xFF;   // Bits 8-15: salidas 1-8

// ── 3. INTERPRETACIÓN DE ERRORES DE RESPUESTA ──
let errorMsg = null;
if (respError) {
    const errCodes = {
        1: 'CMD_INVALIDO: comando conocido pero no ejecutable',
        2: 'TIMEOUT: peso no estable en tiempo límite',
        4: 'CMD_DESCONOCIDO: comando no soportado',
        8: 'VALOR_INVALIDO: valor fuera de rango',
        16: 'CMD_ABORTADO: operación cancelada',
        32: 'PASO_FALLIDO: error en secuencia multi-paso',
        64: 'TEST_FALLIDO: error en comando de test'
    };
    errorMsg = errCodes[respValue] || `ERROR_DESCONOCIDO: ${respValue}`;
}

// ── 4. CONSTRUIR SALIDAS ORGANIZADAS ──
msg.peso = {
    valor: weight,
    unidad: weightUnit,
    estable: motion === 0,
    dataOk: dataOk === 1,
    modoNeto: netMode === 1,
    centroZero: centerOfZero === 1,
    alarma: alarmCond === 1,
    heartbeat: heartbeat,
    unidadAlternativa: altUnit === 1
};

msg.respuesta = {
    codigo: respValue,
    canal: respChannel,
    error: respError === 1,
    mensajeError: errorMsg,
    enProceso: respValue === 2047,
    pasoExitoso: respValue === 2046
};

msg.alarmas = redAlert;

msg.bascula = {
    unidad: weightUnit,
    rango: rangeBits + 1,
    minWeighError: minWeighError === 1,
    enSetup: inSetup === 1,
    falloZeroInicial: puzFail === 1,
    gwpFueraTol: gwpOutTol === 1
};

msg.io = {
    entradasRaw: ioIn,
    salidasRaw: ioOut,
    in1: (ioIn >> 0) & 1, in2: (ioIn >> 1) & 1,
    in3: (ioIn >> 2) & 1, in4: (ioIn >> 3) & 1,
    out1: (ioOut >> 0) & 1, out2: (ioOut >> 1) & 1,
    out3: (ioOut >> 2) & 1, out4: (ioOut >> 3) & 1
};

msg.debug_raw = {
    sequenceBits: sequenceBits,
    mbResponseRaw: resp,
    sbResponseRaw: raw.sbResponse,
    sg1Raw: '0x' + sg1.toString(16).padStart(4,'0'),
    sg2Raw: '0x' + sg2.toString(16).padStart(4,'0'),
    sg3Raw: '0x' + sg3.toString(16).padStart(4,'0')
};

// Resumen legible para el nodo status
const estadoTexto = motion === 0 ? '✅ESTABLE' : '⚡MOVIMIENTO';
const dataTexto = dataOk === 1 ? '' : ' ❌DATA_ERR';
const errTexto = errorMsg ? ` | ⚠️${errorMsg}` : '';
msg.resumen = `${weight} ${weightUnit} | ${estadoTexto}${dataTexto}${errTexto}`;

node.status({
    fill: dataOk ? (motion ? 'yellow' : 'green') : 'red',
    shape: 'dot',
    text: msg.resumen
});

return msg;

// ═══════════════════════════════════════════════════════
// CONSTRUCTOR DE COMANDOS SAI PARA EL ACT350
// ═══════════════════════════════════════════════════════
// Envia cada campo por separado a nodos eip-io out individuales
// ═══════════════════════════════════════════════════════
// Entrada: msg.comando = {
//   codigo: <SAI command number>,
//   valor:  <float32 value>,
//   sbComando: <status block command>
// }
// ═══════════════════════════════════════════════════════

const cmd = msg.comando || {};
const codigo  = cmd.codigo    || 0;
const valor   = cmd.valor     || 0.0;
const sbCmd   = cmd.sbComando || 0;

// Salida 1: FLOAT32 Command Value → offset 0
const msg1 = { payload: valor };

// Salida 2: UINT16 Channel Mask → offset 4 (siempre 0 para single device)
const msg2 = { payload: 0 };

// Salida 3: INT16 MB Command → offset 6
const msg3 = { payload: codigo };

// Salida 4: INT16 SB Command → offset 14
const msg4 = { payload: sbCmd };

const cmdNames = {
    0:'PesoBruto', 2:'PesoTara', 3:'PesoNeto',
    201:'PresetTara', 400:'TaraEstable', 401:'ZeroEstable',
    402:'ClearTara', 403:'TaraInm', 404:'ZeroInm',
    2000:'NOOP', 2004:'Cancelar'
};
node.status({
    fill: 'blue', shape: 'ring',
    text: `→ ${cmdNames[codigo]||codigo}${valor?' ('+valor+')':''}`
});

return [msg1, msg2, msg3, msg4];
